# boot_configure.py — Template for TDA54 VDK core boot configuration
# Generated by vdk-tda54 skill. Copy to your vpconfig directory and customize.
#
# This script runs at Begin of Simulation via simprobe.
# It uses the mock boot code running on ROT_M55 to configure which cores
# come out of reset and at what vector addresses.
#
# Setup:
#   1. Add <WS>/software/bootcode_M55/ to VPConfig → Images → ROT → InitialIm
#   2. Add ${vpconfDir}/boot_configure.py to VPConfig → Scripting → Begin of Simulation
#
# Where <WS> = /work/ti-sdk/workspace/<workspace_name>  (container path)

import bootcode_utils

# --- Configure which cores to start ---
# First argument:  core name string (see list below)
# Second argument: reset vector address (entry point of your firmware ELF)
#
# Available core names:
#   "Main_M55_0"
#   "A720 Core0" .. "A720 Core7"
#   "C7x_0" .. "C7x_3"
#   "RTSS_0_R52_CORE0", "RTSS_1_R52_CORE0"  (R52Plus boot processor cores)

# Example: Bring A720 Core0 out of reset at Linux/RTOS entry point
bootcode_utils.configure_core_out_of_reset("A720 Core0", 0x80000000)

# Example: Bring Main M55_0 out of reset
# bootcode_utils.configure_core_out_of_reset("Main_M55_0", 0x67000000)

# Example: Bring R52Plus core 0 out of reset
# bootcode_utils.configure_core_out_of_reset("RTSS_0_R52_CORE0", 0x00000000)

# Example: Bring C7x DSP 0 out of reset
# bootcode_utils.configure_core_out_of_reset("C7x_0", 0x00000000)
